function ek_no($empNo=''){global $db;$prefix='EKPI-'.date('Ym');$r=$db->fetch("SELECT employee_kpi_no FROM erp_employee_kpi WHERE employee_kpi_no LIKE ? ORDER BY employee_kpi_no DESC LIMIT 1",array($prefix.'%'));$n=$r?((int)substr($r->employee_kpi_no,-4)+1):1;return $prefix.sprintf('%04d',$n);}
function ek_filters($src){return array('as_of'=>isset($src['as_of_date'])&&$src['as_of_date']!==''?$src['as_of_date']:date('Y-m-d'),'cycle_year'=>isset($src['cycle_year'])?trim($src['cycle_year']):'','appraisal_period'=>isset($src['appraisal_period'])?trim($src['appraisal_period']):'','employee_id'=>isset($src['employee_id'])?trim($src['employee_id']):'','department_code'=>isset($src['department_code'])?trim($src['department_code']):'','job_title_id'=>isset($src['job_title_id'])?trim($src['job_title_id']):'','kpi_template_id'=>isset($src['kpi_template_id'])?trim($src['kpi_template_id']):'','target_status'=>isset($src['target_status'])?trim($src['target_status']):'','approval_status'=>isset($src['approval_status'])?trim($src['approval_status']):'','weight_status'=>isset($src['weight_status'])?trim($src['weight_status']):'','keyword'=>isset($src['keyword'])?trim($src['keyword']):'');}
function ek_where($f,&$p){$w=" WHERE ek.effective_from<=? AND ek.effective_to>=? ";array_push($p,$f['as_of'],$f['as_of']);foreach(array('cycle_year','appraisal_period','department_code','target_status','approval_status') as $k){if($f[$k]!==''){$w.=" AND ek.$k=? ";$p[]=$f[$k];}}foreach(array('employee_id','job_title_id','kpi_template_id') as $k){if($f[$k]!==''){$w.=" AND ek.$k=? ";$p[]=(int)$f[$k];}}if($f['weight_status']==='COMPLETE')$w.=" AND ROUND(ek.total_weight,2)=100.00 ";elseif($f['weight_status']==='INCOMPLETE')$w.=" AND ROUND(ek.total_weight,2)<>100.00 ";if($f['keyword']!==''){$kw='%'.$f['keyword'].'%';$w.=" AND (ek.employee_kpi_no LIKE ? OR e.employee_no LIKE ? OR e.full_name LIKE ? OR d.nm_dept LIKE ? OR jt.job_title_name LIKE ? OR kt.template_name LIKE ? OR ek.sap_reference LIKE ?) ";for($i=0;$i<7;$i++)$p[]=$kw;}return $w;}
function ek_row($id){global $db;return $db->fetch("SELECT ek.*,e.employee_no,e.full_name,e.employee_group,d.nm_dept,jt.job_title_code,jt.job_title_name,kt.template_no,kt.template_name,ap.employee_no appraiser_no,ap.full_name appraiser_name,hr.employee_no hr_no,hr.full_name hr_name FROM erp_employee_kpi ek JOIN erp_employee_master e ON e.id=ek.employee_id LEFT JOIN dept d ON d.kd_dept=ek.department_code LEFT JOIN erp_job_title jt ON jt.id=ek.job_title_id LEFT JOIN erp_kpi_template kt ON kt.id=ek.kpi_template_id LEFT JOIN erp_employee_master ap ON ap.id=ek.appraiser_employee_id LEFT JOIN erp_employee_master hr ON hr.id=ek.hr_reviewer_employee_id WHERE ek.id=? LIMIT 1",array((int)$id));}
