  $codes=isset($_POST['kpi_code'])?$_POST['kpi_code']:array();$lineData=array();$total=0;$line=1;for($i=0;$i<count($codes);$i++){if(trim($codes[$i])==='')continue;$w=(float)$_POST['weight'][$i];if($w<=0)ek_json('error','Weight detail KPI harus lebih dari 0.');$total+=$w;$score=$_POST['score'][$i]!==''?(float)$_POST['score'][$i]:null;$lineData[]=array('template_detail_id'=>$_POST['template_detail_id'][$i]!==''?(int)$_POST['template_detail_id'][$i]:null,'line_no'=>$line++,'kpi_code'=>strtoupper(trim($codes[$i])),'kpi_name'=>trim($_POST['kpi_name'][$i]),'kpi_perspective'=>$_POST['kpi_perspective'][$i],'measure_type'=>$_POST['measure_type'][$i],'target_value'=>$_POST['target_value'][$i]!==''?(float)$_POST['target_value'][$i]:null,'target_text'=>trim($_POST['target_text'][$i]),'unit_of_measure'=>trim($_POST['unit_of_measure'][$i]),'weight'=>$w,'scoring_direction'=>$_POST['scoring_direction'][$i],'minimum_score'=>$_POST['minimum_score'][$i]!==''?(float)$_POST['minimum_score'][$i]:0,'maximum_score'=>$_POST['maximum_score'][$i]!==''?(float)$_POST['maximum_score'][$i]:100,'data_source'=>trim($_POST['data_source'][$i]),'review_frequency'=>$_POST['review_frequency'][$i],'mandatory'=>$_POST['mandatory'][$i],'actual_value'=>$_POST['actual_value'][$i]!==''?(float)$_POST['actual_value'][$i]:null,'actual_text'=>trim($_POST['actual_text'][$i]),'score'=>$score,'weighted_score'=>$score!==null?round(($score*$w)/100,2):null,'remarks'=>trim($_POST['detail_remarks'][$i]));}
